      fr: { title: "Jeux de Guerre - Partie 1", location: "Avant-poste criminel – Parler à Sir. B", description: "Le Syndicat se prépare pour un raid sur Fort Emberreach. Nous allons avoir besoin de tout le monde pour cette opération. Pénétrez dans la base, volez leurs armes et tuez tout le monde.", howToComplete: "Piratez 1 caisse sécurisée, ouvrez 10 coffres militaires et faites 10 éliminations à la base militaire." },
      de: { title: "Kriegsspiele - Teil 1", location: "Krimineller Außenposten – Sprich mit Sir. B", description: "Das Syndikat bereitet einen Überfall auf Fort Emberreach vor. Wir brauchen jeden Mann für diese Operation. Brich in die Basis ein, plündere ihre Waffen und töte jeden, den du siehst.", howToComplete: "Hacke 1 sichere Kiste, öffne 10 Militärtruhen und erziele 10 Kills beim Militär." },
      es: { title: "Juegos de Guerra - Parte 1", location: "Puesto de avanzada criminal: habla con Sir. B", description: "El Sindicato se está preparando para un asalto a Fort Emberreach. Necesitaremos a todos los que podamos para esta operación. Entra en la base, saquea sus armas y mata a todos los que veas.", howToComplete: "Hackea 1 caja segura, abre 10 cofres militares y consigue 10 bajas en la base militar." },
      pt: { title: "Jogos de Guerra - Parte 1", location: "Posto Avançado Criminoso – Fale com Sir. B", description: "O Sindicato está si preparando para um ataque ao Fort Emberreach. Precisaremos de todos que pudermos para esta operação. Invada a base, saqueie as armas deles e mate todos que encontrar.", howToComplete: "Hackeie 1 Crate Seguro, abra 10 Baús Militares e consiga 10 abates no Militar." },
      ru: { title: "Военные игры — Часть 1", location: "Криминальный аванпост — поговорите с Сиром Б.", description: "Синдикат готовится к рейду на Форт Эмберрич. Нам понадобятся все силы для этой операции. Проберись на базу, разграбь их арсенал и уничтожь всех на своем пути.", howToComplete: "Взломайте 1 защищенный ящик, откройте 10 военных сундуков и убейте 10 врагов на военной базе." },
      ar: { title: "ألعاب الحرب - الجزء 1", location: "المخفر الإجرامي - تحدث إلى السير ب", description: "تستعد المنظمة لشن غارة على حصن \"إيمبريتش\" (Fort Emberreach). سنحتاج إلى كل شخص يمكننا الحصول عليه لهذه العملية. اقتحم القاعدة، وانهب أسلحتهم، واقتل كل من تراه.", howToComplete: "قم باختراق صندوق آمن واحد، وافتح 10 صناديق عسكرية، واحصل على 10 عمليات قتل في القاعدة العسكرية." },
      tr: { title: "Savaş Oyunları - Bölüm 1", location: "Suçlu Karakolu – Sir. B ile Konuş", description: "Sendika, Fort Emberreach'e bir baskın düzenlemek için hazırlanıyor. Bu operasyon için elimizden gelen herkesi toplamamız gerekecek. Üsse gir, silahlarını yağmala ve gördüğün her şeyi öldür.", howToComplete: "1 Güvenli Kasayı hackle, 10 Askeri Sandık aç ve Askeriyede 10 leş al." },
      zh: { title: "战争游戏 - 第 1 部分", location: "犯罪据点 – 与 Sir. B 对话", description: "辛迪加正准备突袭埃姆伯里奇堡。这次行动我们需要尽可能多的人手。潜入基地，搜刮他们的武器，并干掉任何你看到的人。", howToComplete: "黑入 1 个安全板箱、开启 10 个军事箱并在军事区获得 10 次击杀。" }
